  1→import { WALL_HEIGHT } from './defaults';
  2→import { generateId } from './ids';
  3→import { createAnnotationSettings, createFloor } from './models';
  4→
  5→export const DEFAULT_FLOOR_TO_FLOOR_HEIGHT = WALL_HEIGHT;
  6→
  7→function sortByLevelAndElevation(a, b) {
  8→  const levelIndexDiff = getFloorLevelIndex(a) - getFloorLevelIndex(b);
  9→  if (levelIndexDiff !== 0) return levelIndexDiff;
 10→
 11→  const elevationDiff = getFloorElevation(a) - getFloorElevation(b);
 12→  if (elevationDiff !== 0) return elevationDiff;
 13→
 14→  return (a.name || '').localeCompare(b.name || '');
 15→}
 16→
 17→function clonePoint(point) {
 18→  return point ? { x: point.x, y: point.y } : point;
 19→}
 20→
 21→function cloneAttachment(attachment, columnIdMap) {
 22→  if (!attachment) return null;
 23→
 24→  return {
 25→    ...attachment,
 26→    columnId: attachment.columnId ? (columnIdMap.get(attachment.columnId) || attachment.columnId) : attachment.columnId,
 27→  };
 28→}
 29→
 30→function cloneWall(wall, columnIdMap) {
 31→  return {
 32→    ...wall,
 33→    id: generateId('wall'),
 34→    start: clonePoint(wall.start),
 35→    end: clonePoint(wall.end),
 36→    startAttachment: cloneAttachment(wall.startAttachment, columnIdMap),
 37→    endAttachment: cloneAttachment(wall.endAttachment, columnIdMap),
 38→  };
 39→}
 40→
 41→function cloneRoom(room) {
 42→  return {
 43→    ...room,
 44→    id: generateId('room'),
 45→    points: (room.points || []).map(clonePoint),
 46→    labelPosition: clonePoint(room.labelPosition),
 47→  };
 48→}
 49→
 50→function cloneDoor(door, wallIdMap) {
 51→  return {
 52→    ...door,
 53→    id: generateId('door'),
 54→    wallId: wallIdMap.get(door.wallId) || door.wallId,
 55→  };
 56→}
 57→
 58→function cloneWindow(windowItem, wallIdMap) {
 59→  return {
 60→    ...windowItem,
 61→    id: generateId('win'),
 62→    wallId: wallIdMap.get(windowItem.wallId) || windowItem.wallId,
 63→  };
 64→}
 65→
 66→function cloneColumn(column) {
 67→  return {
 68→    ...column,
 69→    id: generateId('col'),
 70→  };
 71→}
 72→
 73→function cloneBeam(beam, columnIdMap, elevationDelta) {
 74→  return {
 75→    ...beam,
 76→    id: generateId('beam'),
 77→    startRef: beam.startRef
 78→      ? { ...beam.startRef, id: columnIdMap.get(beam.startRef.id) || beam.startRef.id }
 79→      : null,
 80→    endRef: beam.endRef
 81→      ? { ...beam.endRef, id: columnIdMap.get(beam.endRef.id) || beam.endRef.id }
 82→      : null,
 83→    floorLevel: (beam.floorLevel ?? 0) + elevationDelta,
 84→  };
 85→}
 86→
 87→function cloneStair(stair, sourceFloorId, duplicatedFloorId) {
 88→  return {
 89→    ...stair,
 90→    id: generateId('stair'),
 91→    startPoint: clonePoint(stair.startPoint),
 92→    direction: stair.direction ? { ...stair.direction } : { angle: 0 },
 93→    floorRelation: {
 94→      fromFloorId: stair.floorRelation?.fromFloorId === sourceFloorId ? duplicatedFloorId : (stair.floorRelation?.fromFloorId ?? duplicatedFloorId),
 95→      toFloorId: stair.floorRelation?.toFloorId === sourceFloorId ? duplicatedFloorId : (stair.floorRelation?.toFloorId ?? duplicatedFloorId),
 96→    },
 97→  };
 98→}
 99→
100→function cloneAnnotation(annotation) {
101→  return {
102→    ...annotation,
103→    id: generateId('anno'),
104→    startPoint: clonePoint(annotation.startPoint),
105→    endPoint: clonePoint(annotation.endPoint),
106→  };
107→}
108→
109→function cloneSlab(slab, floorId, elevationDelta) {
110→  return {
111→    ...slab,
112→    id: generateId('slab'),
113→    floorId,
114→    boundaryPoints: (slab.boundaryPoints || []).map(clonePoint),
115→    elevation: (slab.elevation ?? 0) + elevationDelta,
116→  };
117→}
118→
119→function cloneSectionCut(sectionCut) {
120→  return {
121→    ...sectionCut,
122→    id: generateId('section'),
123→    startPoint: clonePoint(sectionCut.startPoint),
124→    endPoint: clonePoint(sectionCut.endPoint),
125→  };
126→}
127→
128→export function getDefaultFloorName(levelIndex = 0) {
129→  if (levelIndex === 0) return 'Ground Floor';
130→  if (levelIndex < 0) return `Basement ${Math.abs(levelIndex)}`;
131→  return `Floor ${levelIndex}`;
132→}
133→
134→export function getFloorLevelIndex(floor, fallbackIndex = 0) {
135→  if (!floor) return fallbackIndex;
136→  if (Number.isFinite(floor.levelIndex)) return floor.levelIndex;
137→  if (Number.isFinite(floor.level)) return floor.level;
138→  return fallbackIndex;
139→}
140→
141→export function getFloorToFloorHeight(floor) {
142→  return floor?.floorToFloorHeight ?? DEFAULT_FLOOR_TO_FLOOR_HEIGHT;
143→}
144→
145→export function getFloorElevation(floor, fallbackIndex = 0) {
146→  if (!floor) return 0;
147→  if (Number.isFinite(floor.elevation)) return floor.elevation;
148→  if (Number.isFinite(floor.level)) return floor.level;
149→  return getFloorLevelIndex(floor, fallbackIndex) * getFloorToFloorHeight(floor);
150→}
151→
152→export function sortFloors(floors = []) {
153→  return [...floors].sort(sortByLevelAndElevation);
154→}
155→
156→export function getOrderedFloors(projectOrFloors) {
157→  const floors = Array.isArray(projectOrFloors)
158→    ? projectOrFloors
159→    : (projectOrFloors?.floors || []);
160→  return sortFloors(floors);
161→}
162→
163→export function getProjectFloor(project, floorId) {
164→  return (project?.floors || []).find((floor) => floor.id === floorId) || null;
165→}
166→
167→export function getDefaultActiveFloorId(project, preferredFloorId = null) {
168→  const orderedFloors = getOrderedFloors(project);
169→  if (!orderedFloors.length) return null;
170→  if (preferredFloorId && orderedFloors.some((floor) => floor.id === preferredFloorId)) {
171→    return preferredFloorId;
172→  }
173→  return orderedFloors[0].id;
174→}
175→
176→export function shiftFloorElevationData(floor, deltaElevation = 0) {
177→  if (!deltaElevation) return { ...floor };
178→
179→  return {
180→    ...shiftFloorAbsoluteElements(floor, deltaElevation),
181→    elevation: getFloorElevation(floor) + deltaElevation,
182→  };
183→}
184→
185→export function shiftFloorAbsoluteElements(floor, deltaElevation = 0) {
186→  if (!deltaElevation) return { ...floor };
187→
188→  return {
189→    ...floor,
