100→export function createSelectHandler({ dispatch, editorDispatch, getFloor, activeFloorId, viewport, snapEnabled }) {
101→  return {
102→    onMouseDown(modelPos, e, toolState) {
103→      if (e.button !== 0) return;
104→
105→      const floor = getFloor(activeFloorId);
106→      if (!floor) return;
107→
108→      // Check if clicking a handle
109→      const target = e.target;
110→      if (target.dataset.handle) {
111→        editorDispatch({
112→          type: 'UPDATE_TOOL_STATE',
113→          payload: {
114→            dragging: true,
115→            dragType: 'handle',
116→            handle: target.dataset.handle,
117→            handleIndex: target.dataset.index != null ? Number(target.dataset.index) : null,
118→            startPos: modelPos,
119→          },
120→        });
121→        return;
122→      }
123→
124→      const hit = hitTest(modelPos, floor, SNAP_DISTANCE_PX / viewport.zoom * 2.5);
125→      if (hit) {
126→        editorDispatch({ type: 'SELECT_OBJECT', id: hit.id, objectType: hit.type });
127→        const draggableTypes = new Set(['wall', 'column', 'door', 'window', 'stair', 'sectionCut']);
128→        if (!draggableTypes.has(hit.type)) return;
129→        editorDispatch({
130→          type: 'UPDATE_TOOL_STATE',
131→          payload: {
132→            dragging: true,
133→            dragType: 'move',
134→            startPos: modelPos,
135→            originalPos: modelPos,
136→          },
137→        });
138→      } else {
139→        editorDispatch({
140→          type: 'UPDATE_TOOL_STATE',
141→          payload: {
142→            dragging: true,
143→            dragType: 'marquee',
144→            startPos: modelPos,
145→            currentPos: modelPos,
146→          },
147→        });
148→      }
149→    },
150→
151→    onMouseMove(modelPos, e, toolState, selectedId, selectedType) {
152→      if (toolState.dragging && toolState.dragType === 'marquee') {
153→        editorDispatch({
154→          type: 'UPDATE_TOOL_STATE',
155→          payload: { currentPos: modelPos },
156→        });
157→        return;
158→      }
159→
160→      if (!toolState.dragging || !selectedId) return;
161→
162→      const floor = getFloor(activeFloorId);
163→      if (!floor) return;
164→      const dx = modelPos.x - toolState.startPos.x;
165→      const dy = modelPos.y - toolState.startPos.y;
166→      const snapDistModel = SNAP_DISTANCE_PX / viewport.zoom;
167→
168→      if (selectedType === 'wall') {
169→        const wall = floor.walls.find(w => w.id === selectedId);
170→        if (!wall) return;
171→        const resolved = resolveWallEndpoints(wall, floor.columns || []);
172→
173→        if (toolState.dragType === 'handle') {
174→          const handle = toolState.handle;
175→          const oppositeKey = handle === 'start' ? 'end' : 'start';
176→          const oppositePoint = resolved[oppositeKey];
177→          let nextPoint = modelPos;
178→          let nextAttachment = null;
179→
180→          if (e.shiftKey) {
181→            const dx = modelPos.x - oppositePoint.x;
182→            const dy = modelPos.y - oppositePoint.y;
183→            const angle = Math.atan2(dy, dx);
184→            const snapAngle = Math.round(angle / (Math.PI / 4)) * (Math.PI / 4);
185→            const len = Math.sqrt(dx * dx + dy * dy);
186→            nextPoint = {
187→              x: oppositePoint.x + Math.cos(snapAngle) * len,
188→              y: oppositePoint.y + Math.sin(snapAngle) * len,
189→            };
190→          } else if (snapEnabled) {
191→            const snapResult = snapWallEndpoint(modelPos, {
192→              walls: floor.walls,
193→              columns: floor.columns || [],
194→              snapDist: snapDistModel,
195→              otherPoint: oppositePoint,
196→              ignoreWallId: wall.id,
197→            });
198→            if (snapResult) {
199→              nextPoint = snapResult.point;
200→              nextAttachment = snapResult.attachment;
201→            }
202→          }
203→
204→          if (distance(nextPoint, oppositePoint) < MIN_WALL_LENGTH) return;
205→
206→          dispatch({
207→            type: 'WALL_UPDATE',
208→            floorId: activeFloorId,
209→            wall: {
210→              id: wall.id,
211→              [handle]: nextPoint,
212→              [`${handle}Attachment`]: nextAttachment,
213→            },
214→          });
215→        } else {
216→          let nextStart = { x: resolved.start.x + dx, y: resolved.start.y + dy };
217→          let nextEnd = { x: resolved.end.x + dx, y: resolved.end.y + dy };
218→          let startAttachment = null;
219→          let endAttachment = null;
220→
221→          if (snapEnabled) {
222→            const startSnap = snapWallEndpoint(nextStart, {
223→              walls: floor.walls,
224→              columns: floor.columns || [],
225→              snapDist: snapDistModel,
226→              otherPoint: nextEnd,
227→              ignoreWallId: wall.id,
228→            });
229→            if (startSnap) {
230→              nextStart = startSnap.point;
231→              startAttachment = startSnap.attachment;
232→            }
233→
234→            const endSnap = snapWallEndpoint(nextEnd, {
235→              walls: floor.walls,
236→              columns: floor.columns || [],
237→              snapDist: snapDistModel,
238→              otherPoint: nextStart,
239→              ignoreWallId: wall.id,
240→            });
241→            if (endSnap) {
242→              nextEnd = endSnap.point;
243→              endAttachment = endSnap.attachment;
244→            }
245→          }
246→
247→          if (distance(nextStart, nextEnd) < MIN_WALL_LENGTH) return;
248→
249→          dispatch({
250→            type: 'WALL_UPDATE',
251→            floorId: activeFloorId,
252→            wall: {
253→              id: wall.id,
254→              start: nextStart,
255→              end: nextEnd,
256→              startAttachment,
257→              endAttachment,
258→            },
259→          });
260→        }
261→        editorDispatch({
262→          type: 'UPDATE_TOOL_STATE',
263→          payload: { startPos: modelPos },
264→        });
265→      } else if (selectedType === 'column') {
266→        const col = (floor.columns || []).find(c => c.id === selectedId);
267→        if (!col) return;
268→        dispatch({
269→          type: 'COLUMN_UPDATE',
270→          floorId: activeFloorId,
271→          column: { id: col.id, x: col.x + dx, y: col.y + dy },
272→        });
273→        editorDispatch({
274→          type: 'UPDATE_TOOL_STATE',
275→          payload: { startPos: modelPos },
276→        });
277→      } else if (selectedType === 'sectionCut') {
278→        const sectionCut = (floor.sectionCuts || []).find(s => s.id === selectedId);
279→        if (!sectionCut) return;
280→
281→        if (toolState.dragType === 'handle') {
282→          const handle = toolState.handle;
283→          const nextSectionCut = handle === 'start'
284→            ? { ...sectionCut, startPoint: modelPos }
285→            : { ...sectionCut, endPoint: modelPos };
286→
287→          if (distance(nextSectionCut.startPoint, nextSectionCut.endPoint) < MIN_WALL_LENGTH) return;
288→
289→          dispatch({
290→            type: 'SECTION_UPDATE',
291→            floorId: activeFloorId,
292→            sectionCut: nextSectionCut,
293→          });
294→        } else {
295→          dispatch({
296→            type: 'SECTION_UPDATE',
297→            floorId: activeFloorId,
298→            sectionCut: {
299→              id: sectionCut.id,
300→              startPoint: {
301→                x: sectionCut.startPoint.x + dx,
302→                y: sectionCut.startPoint.y + dy,
303→              },
304→              endPoint: {
305→                x: sectionCut.endPoint.x + dx,
306→                y: sectionCut.endPoint.y + dy,
307→              },
308→            },
309→          });
310→          editorDispatch({
311→            type: 'UPDATE_TOOL_STATE',
312→            payload: { startPos: modelPos },
313→          });
314→        }
315→      } else if (selectedType === 'beam') {
316→        return;
317→      } else if (selectedType === 'stair') {
318→        const stair = (floor.stairs || []).find(entry => entry.id === selectedId);
319→        if (!stair) return;
320→        dispatch({
321→          type: 'STAIR_UPDATE',
322→          floorId: activeFloorId,
323→          stair: {
324→            id: stair.id,
325→            startPoint: {
326→              x: stair.startPoint.x + dx,
327→              y: stair.startPoint.y + dy,
328→            },
329→          },
330→        });
331→        editorDispatch({
332→          type: 'UPDATE_TOOL_STATE',
333→          payload: { startPos: modelPos },
334→        });
335→      } else if (selectedType === 'slab') {
336→        if (toolState.dragType !== 'handle' || toolState.handle !== 'slab-vertex' || toolState.handleIndex == null) {
337→          return;
338→        }
339→        const slab = (floor.slabs || []).find(s => s.id === selectedId);
340→        if (!slab) return;
341→
342→        const boundaryPoints = slab.boundaryPoints.map((point, index) => (
343→          index === toolState.handleIndex ? { x: modelPos.x, y: modelPos.y } : point
344→        ));
345→
346→        dispatch({
347→          type: 'SLAB_UPDATE',
348→          floorId: activeFloorId,
349→          slab: {
350→            id: slab.id,
351→            boundaryPoints,
352→          },
353→        });
354→        editorDispatch({
355→          type: 'UPDATE_TOOL_STATE',
356→          payload: { startPos: modelPos },
357→        });
358→      } else if (selectedType === 'door' || selectedType === 'window') {
359→        // Slide along parent wall
360→        const items = selectedType === 'door' ? floor.doors : floor.windows;
361→        const item = items.find(i => i.id === selectedId);
362→        if (!item) return;
363→
364→        const wall = floor.walls.find(w => w.id === item.wallId);
365→        if (!wall) return;
366→
367→        const newOffset = projectPointOnWall(wall, modelPos);
368→        const halfWidth = item.width / 2;
369→        const maxOffset = wallLength(wall) - halfWidth;
370→        const clampedOffset = Math.max(halfWidth, Math.min(maxOffset, newOffset));
371→
372→        const updateType = selectedType === 'door' ? 'DOOR_UPDATE' : 'WINDOW_UPDATE';
373→        dispatch({
374→          type: updateType,
375→          floorId: activeFloorId,
376→          [selectedType]: { id: item.id, offset: clampedOffset },
377→        });
378→
379→        editorDispatch({
380→          type: 'UPDATE_TOOL_STATE',
381→          payload: { startPos: modelPos },
382→        });
383→      }
384→    },
385→
386→    onMouseUp(modelPos, e, toolState) {
387→      if (toolState.dragging && toolState.dragType === 'marquee') {
388→        const floor = getFloor(activeFloorId);
389→        const bounds = normalizeRectBounds(toolState.startPos || modelPos, toolState.currentPos || modelPos);
390→        const size = rectSize(bounds);
391→        const minimumSize = SNAP_DISTANCE_PX / viewport.zoom;
392→
393→        if (!floor || (size.width < minimumSize && size.height < minimumSize)) {
394→          editorDispatch({ type: 'DESELECT' });
395→        } else {
396→          const regionSelection = collectPlanRegionSelection(floor, bounds);
397→          if (regionSelection.objectCount) {
398→            editorDispatch({
399→              type: 'SET_REGION_SELECTION',
400→              bounds: regionSelection.bounds,
401→              selection: regionSelection.selection,
402→            });
403→          } else {
404→            editorDispatch({ type: 'DESELECT' });
405→          }
406→        }
407→
408→        editorDispatch({
409→          type: 'UPDATE_TOOL_STATE',
410→          payload: {
411→            dragging: false,
412→            dragType: null,
413→            handle: null,
414→            handleIndex: null,
415→            startPos: null,
416→            currentPos: null,
417→          },
418→        });
419→        return;
420→      }
421→
422→      if (toolState.dragging) {
423→        editorDispatch({
424→          type: 'UPDATE_TOOL_STATE',
425→          payload: {
426→            dragging: false,
