  2→import { useProject } from '@/app/ProjectProvider';
  3→import { useEditor } from '@/app/EditorProvider';
  4→import { getBeamDisplayLabel } from '@/domain/beamLabels';
  5→import { getColumnListLabel } from '@/domain/columnLabels';
  6→import { createFloorAboveHighest, getFloorElevation, getFloorLevelIndex, getOrderedFloors } from '@/domain/floorModels';
  7→import { createSheet, getSheetDisplayLabel } from '@/domain/sheetModels';
  8→import { getSlabDisplayLabel } from '@/domain/slabLabels';
  9→import { getStairDisplayLabel } from '@/domain/stairLabels';
 10→import { getAnnotationDisplayLabel } from '@/annotations/format';
 11→import styles from './Sidebar.module.css';
 12→
 13→function Section({ title, count, collapsed, onToggle, collapsible = true, children }) {
 14→  return (
 15→    <div className={styles.section}>
 16→      <button
 17→        type="button"
 18→        className={`${styles.sectionHeader} ${collapsible ? styles.sectionHeaderClickable : ''}`}
 19→        onClick={collapsible ? onToggle : undefined}
 20→        aria-expanded={!collapsed}
 21→      >
 22→        <span className={`${styles.chevron} ${collapsed ? styles.chevronCollapsed : ''}`}>
 23→          {collapsible ? '▾' : ''}
 24→        </span>
 25→        <span className={styles.sectionTitle}>{title}</span>
 26→        {count !== undefined && <span className={styles.count}>{count}</span>}
 27→      </button>
 28→      {!collapsed && children}
 29→    </div>
 30→  );
 31→}
 32→
 33→export default function Sidebar() {
 34→  const { project, dispatch, duplicateFloor } = useProject();
 35→  const { activeFloorId, activeSheetId, selectedId, workspaceMode, dispatch: editorDispatch } = useEditor();
 36→  const orderedFloors = getOrderedFloors(project);
 37→  const floor = orderedFloors.find((entry) => entry.id === activeFloorId) || null;
 38→  const [collapsedSections, setCollapsedSections] = useState({
 39→    floors: false,
 40→    sheets: false,
 41→    slabs: false,
 42→    walls: false,
 43→    annotations: false,
 44→    beams: false,
 45→    stairs: false,
 46→    doors: false,
 47→    windows: false,
 48→    columns: false,
 49→    rooms: false,
 50→  });
 51→
 52→  const selectObject = (id, type) => {
 53→    editorDispatch({ type: 'SELECT_OBJECT', id, objectType: type });
 54→  };
 55→
 56→  const selectFloor = (floorId) => {
 57→    editorDispatch({ type: 'SET_WORKSPACE_MODE', workspaceMode: 'model' });
 58→    editorDispatch({ type: 'SET_ACTIVE_FLOOR', floorId });
 59→    editorDispatch({ type: 'SELECT_OBJECT', id: floorId, objectType: 'floor' });
 60→  };
 61→
 62→  const setActiveFloor = (floorId) => {
 63→    editorDispatch({ type: 'SET_ACTIVE_FLOOR', floorId });
 64→  };
 65→
 66→  const addFloor = () => {
 67→    const nextFloor = createFloorAboveHighest(project.floors || []);
 68→    dispatch({ type: 'FLOOR_ADD', floor: nextFloor });
 69→    selectFloor(nextFloor.id);
 70→  };
 71→
 72→  const handleDuplicateFloor = (floorToDuplicate) => {
 73→    const duplicatedFloor = duplicateFloor(floorToDuplicate.id);
 74→    if (!duplicatedFloor) return;
 75→
 76→    dispatch({ type: 'FLOOR_DUPLICATE', floor: duplicatedFloor });
 77→    selectFloor(duplicatedFloor.id);
 78→  };
 79→
 80→  const handleDeleteFloor = (floorToDelete) => {
 81→    if ((project.floors || []).length <= 1) return;
 82→
 83→    const confirmed = window.confirm(`Delete "${floorToDelete.name}"?`);
 84→    if (!confirmed) return;
 85→
 86→    const remainingFloors = orderedFloors.filter((entry) => entry.id !== floorToDelete.id);
 87→    const fallbackFloor = remainingFloors[0] || null;
 88→
 89→    dispatch({
 90→      type: 'FLOOR_DELETE',
 91→      floorId: floorToDelete.id,
 92→      fallbackFloorId: fallbackFloor?.id ?? null,
 93→    });
 94→
 95→    if (floorToDelete.id === activeFloorId && fallbackFloor) {
 96→      if (workspaceMode === 'model') {
 97→        selectFloor(fallbackFloor.id);
 98→      } else {
 99→        setActiveFloor(fallbackFloor.id);
100→      }
101→    }
102→  };
103→
104→  const addSheet = () => {
105→    const nextIndex = (project.sheets || []).length + 1;
106→    const sheet = createSheet(`Sheet ${nextIndex}`, {
107→      drawingName: `Drawing ${nextIndex}`,
108→    });
109→    dispatch({ type: 'SHEET_ADD', sheet });
110→    editorDispatch({ type: 'SET_ACTIVE_SHEET', sheetId: sheet.id });
111→    editorDispatch({ type: 'SET_WORKSPACE_MODE', workspaceMode: 'sheet' });
112→    editorDispatch({ type: 'SELECT_OBJECT', id: sheet.id, objectType: 'sheet' });
113→  };
114→
115→  const toggleSection = (sectionKey) => {
116→    setCollapsedSections(current => ({
117→      ...current,
118→      [sectionKey]: !current[sectionKey],
119→    }));
120→  };
121→
122→  return (
123→    <div className={styles.sidebar}>
124→      <Section title="Project" collapsible={false}>
125→        <input
126→          className={styles.projectName}
127→          value={project.name}
128→          onChange={(e) => dispatch({ type: 'PROJECT_SET_NAME', name: e.target.value })}
129→        />
130→      </Section>
131→
132→      <Section
133→        title="Floors"
134→        count={orderedFloors.length}
135→        collapsed={collapsedSections.floors}
136→        onToggle={() => toggleSection('floors')}
137→      >
138→        <button type="button" className={styles.item} onClick={addFloor}>
139→          + Add Floor
140→        </button>
141→        {orderedFloors.map((entry) => (
142→          <div key={entry.id} className={styles.floorRow}>
143→            <button
144→              type="button"
145→              className={`${styles.item} ${entry.id === activeFloorId ? styles.itemSelected : ''} ${styles.floorButton}`}
146→              onClick={() => selectFloor(entry.id)}
147→            >
148→              <span className={styles.floorName}>{entry.name}</span>
149→              <span className={styles.floorMeta}>
150→                L{getFloorLevelIndex(entry)} · {Math.round(getFloorElevation(entry))} mm
151→              </span>
152→            </button>
153→            <div className={styles.floorActions}>
154→              <button
155→                type="button"
156→                className={styles.floorActionBtn}
157→                onClick={() => handleDuplicateFloor(entry)}
158→                title={`Duplicate ${entry.name}`}
159→              >
160→                Dup
161→              </button>
162→              <button
163→                type="button"
164→                className={`${styles.floorActionBtn} ${styles.floorActionDanger}`}
165→                onClick={() => handleDeleteFloor(entry)}
166→                title={`Delete ${entry.name}`}
167→                disabled={orderedFloors.length <= 1}
168→              >
169→                Del
170→              </button>
171→            </div>
172→          </div>
173→        ))}
174→      </Section>
175→
176→      <Section
177→        title="Sheets"
178→        count={(project.sheets || []).length}
179→        collapsed={collapsedSections.sheets}
