  1→import { DOOR_HEIGHT, DOOR_SILL_HEIGHT, SLAB_ELEVATION, SLAB_THICKNESS, STAIR_RISERS, STAIR_RISER_HEIGHT, STAIR_TREAD_DEPTH, STAIR_WIDTH, WALL_HEIGHT, WINDOW_HEIGHT, WINDOW_SILL_HEIGHT } from '@/domain/defaults';
  2→import { createFloor } from '@/domain/models';
  3→import { createAnnotationSettings } from '@/domain/models';
  4→import { getDefaultActiveFloorId, getFloorElevation, getFloorLevelIndex, getFloorToFloorHeight, sortFloors } from '@/domain/floorModels';
  5→
  6→export function deserializeProject(json) {
  7→  if (!json || !json.version || !json.data) {
  8→    throw new Error('Invalid project data');
  9→  }
 10→  if (json.version !== 1) {
 11→    throw new Error(`Unsupported project version: ${json.version}`);
 12→  }
 13→
 14→  const project = json.data;
 15→
 16→  // Basic validation
 17→  if (!project.id || !project.name || !Array.isArray(project.floors)) {
 18→    throw new Error('Invalid project structure');
 19→  }
 20→
 21→  if (!Array.isArray(project.sheets)) {
 22→    project.sheets = [];
 23→  }
 24→
 25→  if (project.floors.length === 0) {
 26→    project.floors = [createFloor('Ground Floor', 0)];
 27→  }
 28→
 29→  for (const floor of project.floors) {
 30→    if (!floor.id || !Array.isArray(floor.walls)) {
 31→      throw new Error('Invalid floor structure');
 32→    }
 33→  }
 34→
 35→  // Backfill missing room fields for old saves
 36→  project.floors.forEach((floor, index) => {
 37→    if (!floor.name) floor.name = index === 0 ? 'Ground Floor' : `Floor ${index}`;
 38→    if (floor.levelIndex === undefined) {
 39→      floor.levelIndex = floor.level ?? index;
 40→    }
 41→    if (floor.floorToFloorHeight === undefined) {
 42→      floor.floorToFloorHeight = WALL_HEIGHT;
 43→    }
 44→    if (floor.elevation === undefined) {
 45→      floor.elevation = floor.level ?? (floor.levelIndex * floor.floorToFloorHeight);
 46→    }
 47→    delete floor.level;
 48→
 49→    if (!floor.rooms) floor.rooms = [];
 50→    for (const room of floor.rooms) {
 51→      if (!room.points) room.points = [];
 52→      if (room.area === undefined) room.area = 0;
 53→    }
 54→  });
 55→
 56→  // Backfill door/window type fields for old saves
 57→  for (const floor of project.floors) {
 58→    if (!floor.doors) floor.doors = [];
 59→    for (const door of floor.doors) {
 60→      if (!door.type) door.type = 'swing';
 61→      if (door.height === undefined) door.height = DOOR_HEIGHT;
 62→      if (door.sillHeight === undefined) door.sillHeight = DOOR_SILL_HEIGHT;
 63→    }
 64→    if (!floor.windows) floor.windows = [];
 65→    for (const win of floor.windows) {
 66→      if (!win.type) win.type = 'standard';
 67→      if (!win.openDirection) win.openDirection = 'left';
 68→      if (win.height === undefined) win.height = WINDOW_HEIGHT;
 69→      if (win.sillHeight === undefined) win.sillHeight = WINDOW_SILL_HEIGHT;
 70→    }
 71→    if (!floor.columns) floor.columns = [];
 72→    if (!floor.beams) floor.beams = [];
 73→    if (!floor.stairs) floor.stairs = [];
 74→    if (!floor.annotations) floor.annotations = [];
 75→    floor.annotationSettings = createAnnotationSettings(floor.annotationSettings || {});
 76→    // Migrate single slab → slabs array
 77→    if (floor.slab !== undefined) {
 78→      floor.slabs = floor.slab ? [floor.slab] : [];
 79→      delete floor.slab;
 80→    }
 81→    if (!Array.isArray(floor.slabs)) floor.slabs = [];
 82→    // Migrate single sectionCut → sectionCuts array
 83→    if (floor.sectionCut !== undefined) {
 84→      floor.sectionCuts = floor.sectionCut ? [floor.sectionCut] : [];
 85→      delete floor.sectionCut;
 86→    }
 87→    if (!Array.isArray(floor.sectionCuts)) floor.sectionCuts = [];
 88→    for (const wall of floor.walls) {
 89→      if (wall.height === undefined) wall.height = WALL_HEIGHT;
 90→      if (wall.startAttachment === undefined) wall.startAttachment = null;
 91→      if (wall.endAttachment === undefined) wall.endAttachment = null;
 92→    }
 93→    for (const column of floor.columns) {
 94→      if (column.showLabel === undefined) {
 95→        column.showLabel = Boolean(column.name);
 96→      }
 97→    }
 98→    for (const beam of floor.beams) {
 99→      if (beam.floorLevel === undefined) beam.floorLevel = getFloorElevation(floor, index);
100→    }
101→    for (const stair of floor.stairs) {
102→      if (!stair.startPoint) stair.startPoint = { x: 0, y: 0 };
103→      if (stair.width === undefined) stair.width = STAIR_WIDTH;
104→      if (stair.numberOfRisers === undefined) stair.numberOfRisers = STAIR_RISERS;
105→      if (stair.riserHeight === undefined) stair.riserHeight = STAIR_RISER_HEIGHT;
106→      if (stair.treadDepth === undefined) stair.treadDepth = STAIR_TREAD_DEPTH;
107→      if (stair.direction === undefined) {
108→        stair.direction = { angle: 0 };
109→      } else if (typeof stair.direction === 'number') {
110→        stair.direction = { angle: stair.direction };
111→      } else if (stair.direction.angle === undefined) {
112→        stair.direction.angle = 0;
113→      }
114→      if (stair.floorRelation === undefined) {
115→        stair.floorRelation = { fromFloorId: floor.id, toFloorId: floor.id };
116→      } else {
117→        if (stair.floorRelation.fromFloorId === undefined) stair.floorRelation.fromFloorId = floor.id;
118→        if (stair.floorRelation.toFloorId === undefined) stair.floorRelation.toFloorId = floor.id;
119→      }
120→    }
121→    for (const annotation of floor.annotations) {
122→      if (!annotation.id) {
123→        annotation.id = `anno_${floor.id}_${Math.random().toString(36).slice(2, 8)}`;
124→      }
125→      if (!annotation.type) annotation.type = 'dimension';
126→      if (!annotation.mode) annotation.mode = 'aligned';
127→      if (!annotation.startPoint) annotation.startPoint = { x: 0, y: 0 };
128→      if (!annotation.endPoint) annotation.endPoint = { x: 0, y: 0 };
129→      if (annotation.offset === undefined) annotation.offset = 300;
130→      if (annotation.textOverride === undefined) annotation.textOverride = '';
