  3→import { getBeamRenderData } from '@/geometry/beamGeometry';
  4→import { columnOutline } from '@/geometry/columnGeometry';
  5→import { segmentIntersection } from '@/geometry/line';
  6→import { pointInPolygon } from '@/geometry/polygon';
  7→import { getSectionCutRenderData } from '@/geometry/sectionCutGeometry';
  8→import { getSlabRenderData } from '@/geometry/slabGeometry';
  9→import { getStairRenderData } from '@/geometry/stairGeometry';
 10→import { getWallRenderData } from '@/geometry/wallColumnGeometry';
 11→import { doorOutlineOnWall, windowOutlineOnWall } from '@/geometry/wallGeometry';
 12→
 13→const PLAN_KEYS = ['walls', 'doors', 'windows', 'columns', 'beams', 'stairs', 'annotations', 'slabs', 'sectionCuts', 'rooms'];
 14→
 15→function translatePoint(point, dx, dy) {
 16→  return { x: point.x + dx, y: point.y + dy };
 17→}
 18→
 19→function rectPoints(bounds) {
 20→  return [
 21→    { x: bounds.minX, y: bounds.minY },
 22→    { x: bounds.maxX, y: bounds.minY },
 23→    { x: bounds.maxX, y: bounds.maxY },
 24→    { x: bounds.minX, y: bounds.maxY },
 25→  ];
 26→}
 27→
 28→function pointInRect(point, bounds) {
 29→  return point.x >= bounds.minX &&
 30→    point.x <= bounds.maxX &&
 31→    point.y >= bounds.minY &&
 32→    point.y <= bounds.maxY;
 33→}
 34→
 35→function segmentIntersectsRect(start, end, bounds) {
 36→  if (pointInRect(start, bounds) || pointInRect(end, bounds)) return true;
 37→
 38→  const rect = rectPoints(bounds);
 39→  for (let index = 0; index < rect.length; index += 1) {
 40→    const hit = segmentIntersection(start, end, rect[index], rect[(index + 1) % rect.length]);
 41→    if (hit) return true;
 42→  }
 43→
 44→  return false;
 45→}
 46→
 47→function polygonIntersectsRect(points, bounds) {
 48→  if (!points?.length) return false;
 49→  if (points.some((point) => pointInRect(point, bounds))) return true;
 50→
 51→  const rect = rectPoints(bounds);
 52→  if (rect.some((point) => pointInPolygon(point, points))) return true;
 53→
 54→  for (let index = 0; index < points.length; index += 1) {
 55→    if (segmentIntersectsRect(points[index], points[(index + 1) % points.length], bounds)) {
 56→      return true;
 57→    }
 58→  }
 59→
 60→  return false;
 61→}
 62→
 63→function geometryIntersectsRect(geometry, bounds) {
 64→  if (!geometry) return false;
 65→  if (geometry.polygon) return polygonIntersectsRect(geometry.polygon, bounds);
 66→  if (geometry.segments) {
 67→    return geometry.segments.some((segment) => segmentIntersectsRect(segment.start, segment.end, bounds));
 68→  }
 69→  return false;
 70→}
 71→
 72→function collectGeometryPoints(geometry) {
 73→  if (!geometry) return [];
 74→  if (geometry.polygon) return geometry.polygon;
 75→  if (geometry.segments) {
 76→    return geometry.segments.flatMap((segment) => [segment.start, segment.end]);
 77→  }
 78→  return [];
 79→}
 80→
 81→function cloneAttachment(attachment, nextColumnId = attachment?.columnId ?? null) {
 82→  if (!attachment) return null;
 83→  if (!nextColumnId) return null;
 84→  return {
 85→    ...attachment,
 86→    columnId: nextColumnId,
 87→  };
 88→}
