 90→function createEmptyMap() {
 91→  return PLAN_KEYS.reduce((acc, key) => {
 92→    acc[key] = [];
 93→    return acc;
 94→  }, {});
 95→}
 96→
 97→function toIdSetMap(selection = createEmptyMap()) {
 98→  return PLAN_KEYS.reduce((acc, key) => {
 99→    acc[key] = new Set(selection[key] || []);
100→    return acc;
101→  }, {});
102→}
103→
104→function countSelection(selection = createEmptyMap()) {
105→  return PLAN_KEYS.reduce((count, key) => count + (selection[key]?.length || 0), 0);
106→}
107→
108→function countContent(content = createEmptyMap()) {
109→  return PLAN_KEYS.reduce((count, key) => count + (content[key]?.length || 0), 0);
110→}
111→
112→function idPrefixForKey(key) {
113→  switch (key) {
114→    case 'walls':
115→      return 'wall';
116→    case 'doors':
117→      return 'door';
118→    case 'windows':
119→      return 'win';
120→    case 'columns':
121→      return 'col';
122→    case 'beams':
123→      return 'beam';
124→    case 'stairs':
125→      return 'stair';
126→    case 'annotations':
127→      return 'anno';
128→    case 'slabs':
129→      return 'slab';
130→    case 'sectionCuts':
131→      return 'section';
132→    case 'rooms':
133→      return 'room';
134→    default:
135→      return 'obj';
136→  }
137→}
138→
139→function iteratePlanGeometry(floor, visit) {
140→  const walls = floor?.walls || [];
141→  const columns = floor?.columns || [];
142→
143→  for (const wall of walls) {
144→    visit('walls', wall.id, wall, {
145→      polygon: getWallRenderData(wall, columns).outline,
146→    });
147→  }
148→
149→  for (const door of floor?.doors || []) {
150→    const wall = walls.find((entry) => entry.id === door.wallId);
151→    if (!wall) continue;
152→    const info = doorOutlineOnWall(wall, door);
153→    visit('doors', door.id, door, {
154→      polygon: [info.p1, info.p2, info.p3, info.p4],
155→    });
156→  }
157→
158→  for (const window_ of floor?.windows || []) {
159→    const wall = walls.find((entry) => entry.id === window_.wallId);
160→    if (!wall) continue;
161→    const info = windowOutlineOnWall(wall, window_);
162→    visit('windows', window_.id, window_, {
163→      polygon: [info.p1, info.p2, info.p3, info.p4],
164→    });
165→  }
166→
167→  for (const column of columns) {
168→    visit('columns', column.id, column, {
169→      polygon: columnOutline(column),
170→    });
171→  }
172→
173→  for (const beam of floor?.beams || []) {
174→    const renderData = getBeamRenderData(beam, columns);
175→    if (!renderData) continue;
176→    visit('beams', beam.id, beam, {
177→      polygon: renderData.outline,
178→    });
179→  }
180→
181→  for (const stair of floor?.stairs || []) {
182→    const renderData = getStairRenderData(stair);
183→    if (!renderData) continue;
184→    visit('stairs', stair.id, stair, {
185→      polygon: renderData.outline,
186→    });
187→  }
188→
189→  for (const annotation of floor?.annotations || []) {
190→    const figure = buildManualDimensionFigures([annotation])[0];
191→    if (!figure) continue;
192→    visit('annotations', annotation.id, annotation, {
193→      segments: figure.segments,
194→    });
195→  }
196→
197→  for (const slab of floor?.slabs || []) {
198→    const renderData = getSlabRenderData(slab);
199→    if (!renderData) continue;
200→    visit('slabs', slab.id, slab, {
201→      polygon: renderData.outline,
202→    });
203→  }
204→
205→  for (const sectionCut of floor?.sectionCuts || []) {
206→    const renderData = getSectionCutRenderData(sectionCut);
207→    if (!renderData) continue;
208→    visit('sectionCuts', sectionCut.id, sectionCut, {
209→      segments: [{
210→        start: renderData.line.start,
211→        end: renderData.line.end,
212→      }],
213→    });
214→  }
215→
216→  for (const room of floor?.rooms || []) {
217→    if (!room.points?.length) continue;
218→    visit('rooms', room.id, room, {
219→      polygon: room.points,
220→    });
221→  }
222→}
223→
224→function rebaseWall(wall, anchor, selectedColumns) {
225→  return {
226→    ...wall,
227→    start: translatePoint(wall.start, -anchor.x, -anchor.y),
228→    end: translatePoint(wall.end, -anchor.x, -anchor.y),
229→    startAttachment: selectedColumns.has(wall.startAttachment?.columnId)
230→      ? { ...wall.startAttachment }
231→      : null,
232→    endAttachment: selectedColumns.has(wall.endAttachment?.columnId)
233→      ? { ...wall.endAttachment }
234→      : null,
235→  };
236→}
