264→    ...stair,
265→    startPoint: translatePoint(stair.startPoint, -anchor.x, -anchor.y),
266→    floorRelation: {
267→      fromFloorId: stair.floorRelation?.fromFloorId ?? null,
268→      toFloorId: stair.floorRelation?.toFloorId ?? null,
269→    },
