273→function rebaseAnnotation(annotation, anchor) {
274→  return {
275→    ...annotation,
276→    startPoint: translatePoint(annotation.startPoint, -anchor.x, -anchor.y),
277→    endPoint: translatePoint(annotation.endPoint, -anchor.x, -anchor.y),
278→  };
