281→function rebaseSlab(slab, anchor) {
282→  return {
283→    ...slab,
284→    boundaryPoints: (slab.boundaryPoints || []).map((point) => translatePoint(point, -anchor.x, -anchor.y)),
285→  };
286→}
287→
288→function rebaseSectionCut(sectionCut, anchor) {
289→  return {
290→    ...sectionCut,
291→    startPoint: translatePoint(sectionCut.startPoint, -anchor.x, -anchor.y),
292→    endPoint: translatePoint(sectionCut.endPoint, -anchor.x, -anchor.y),
293→  };
294→}
