296→function rebaseRoom(room, anchor) {
297→  return {
298→    ...room,
299→    points: (room.points || []).map((point) => translatePoint(point, -anchor.x, -anchor.y)),
300→    labelPosition: room.labelPosition
301→      ? translatePoint(room.labelPosition, -anchor.x, -anchor.y)
302→      : null,
303→  };
