306→function translateWall(wall, point) {
307→  return {
308→    ...wall,
309→    start: translatePoint(wall.start, point.x, point.y),
310→    end: translatePoint(wall.end, point.x, point.y),
311→    startAttachment: wall.startAttachment ? { ...wall.startAttachment } : null,
312→    endAttachment: wall.endAttachment ? { ...wall.endAttachment } : null,
313→  };
