316→function translateColumn(column, point) {
317→  return {
318→    ...column,
319→    x: column.x + point.x,
320→    y: column.y + point.y,
321→  };
322→}
323→
324→function translateStair(stair, point) {
325→  return {
326→    ...stair,
327→    startPoint: translatePoint(stair.startPoint, point.x, point.y),
328→    floorRelation: {
329→      fromFloorId: stair.floorRelation?.fromFloorId ?? null,
330→      toFloorId: stair.floorRelation?.toFloorId ?? null,
331→    },
332→  };
333→}
334→
335→function translateAnnotation(annotation, point) {
336→  return {
337→    ...annotation,
338→    startPoint: translatePoint(annotation.startPoint, point.x, point.y),
339→    endPoint: translatePoint(annotation.endPoint, point.x, point.y),
340→  };
341→}
342→
343→function translateSlab(slab, point) {
344→  return {
345→    ...slab,
346→    boundaryPoints: (slab.boundaryPoints || []).map((entry) => translatePoint(entry, point.x, point.y)),
347→  };
348→}
349→
350→function translateSectionCut(sectionCut, point) {
351→  return {
352→    ...sectionCut,
353→    startPoint: translatePoint(sectionCut.startPoint, point.x, point.y),
354→    endPoint: translatePoint(sectionCut.endPoint, point.x, point.y),
355→  };
356→}
