358→function translateRoom(room, point) {
359→  return {
360→    ...room,
361→    points: (room.points || []).map((entry) => translatePoint(entry, point.x, point.y)),
362→    labelPosition: room.labelPosition
363→      ? translatePoint(room.labelPosition, point.x, point.y)
364→      : null,
365→  };
366→}
