368→function translateContent(content, point) {
369→  return {
370→    walls: (content.walls || []).map((wall) => translateWall(wall, point)),
371→    doors: (content.doors || []).map((door) => ({ ...door })),
372→    windows: (content.windows || []).map((window_) => ({ ...window_ })),
373→    columns: (content.columns || []).map((column) => translateColumn(column, point)),
374→    beams: (content.beams || []).map((beam) => ({
375→      ...beam,
376→      startRef: beam.startRef ? { ...beam.startRef } : null,
377→      endRef: beam.endRef ? { ...beam.endRef } : null,
378→    })),
379→    stairs: (content.stairs || []).map((stair) => translateStair(stair, point)),
380→    annotations: (content.annotations || []).map((annotation) => translateAnnotation(annotation, point)),
381→    slabs: (content.slabs || []).map((slab) => translateSlab(slab, point)),
382→    sectionCuts: (content.sectionCuts || []).map((sectionCut) => translateSectionCut(sectionCut, point)),
383→    rooms: (content.rooms || []).map((room) => translateRoom(room, point)),
384→  };
385→}
