387→function buildContentBounds(content) {
388→  const floorLike = { ...content };
389→  const points = [];
390→
391→  iteratePlanGeometry(floorLike, (_, __, ___, geometry) => {
392→    points.push(...collectGeometryPoints(geometry));
393→  });
394→
395→  if (!points.length) return null;
396→
397→  const xs = points.map((point) => point.x);
398→  const ys = points.map((point) => point.y);
399→  return {
400→    minX: Math.min(...xs),
401→    minY: Math.min(...ys),
402→    maxX: Math.max(...xs),
403→    maxY: Math.max(...ys),
404→  };
405→}
406→
407→function cloneSelection(selection) {
408→  return PLAN_KEYS.reduce((acc, key) => {
409→    acc[key] = [...(selection[key] || [])];
410→    return acc;
411→  }, {});
412→}
