422→export function normalizeRectBounds(startPoint, endPoint) {
423→  return {
424→    minX: Math.min(startPoint.x, endPoint.x),
425→    minY: Math.min(startPoint.y, endPoint.y),
426→    maxX: Math.max(startPoint.x, endPoint.x),
427→    maxY: Math.max(startPoint.y, endPoint.y),
428→  };
429→}
