446→export function collectPlanRegionSelection(floor, bounds) {
447→  const selection = createEmptyPlanSelection();
448→
449→  iteratePlanGeometry(floor, (key, id, _, geometry) => {
450→    if (geometryIntersectsRect(geometry, bounds)) {
451→      selection[key].push(id);
452→    }
453→  });
454→
455→  return {
456→    bounds,
457→    selection,
458→    objectCount: countSelection(selection),
