462→export function buildPlanClipboardPayload({ projectId, floorId, floor, regionSelection }) {
463→  const selection = regionSelection?.selection || createEmptyPlanSelection();
464→  const selectionSets = toIdSetMap(selection);
465→  const anchor = {
466→    x: regionSelection?.bounds?.minX || 0,
467→    y: regionSelection?.bounds?.minY || 0,
468→  };
469→  const content = createEmptyPlanContent();
470→
471→  content.walls = (floor.walls || [])
472→    .filter((wall) => selectionSets.walls.has(wall.id))
473→    .map((wall) => rebaseWall(wall, anchor, selectionSets.columns));
474→
475→  content.columns = (floor.columns || [])
476→    .filter((column) => selectionSets.columns.has(column.id))
477→    .map((column) => rebaseColumn(column, anchor));
478→
479→  content.doors = (floor.doors || [])
480→    .filter((door) => selectionSets.doors.has(door.id) && selectionSets.walls.has(door.wallId))
481→    .map((door) => rebaseDoor(door));
482→
483→  content.windows = (floor.windows || [])
484→    .filter((window_) => selectionSets.windows.has(window_.id) && selectionSets.walls.has(window_.wallId))
485→    .map((window_) => rebaseWindow(window_));
486→
487→  content.beams = (floor.beams || [])
488→    .filter((beam) => {
489→      if (!selectionSets.beams.has(beam.id)) return false;
490→      const startId = beam.startRef?.id;
491→      const endId = beam.endRef?.id;
492→      return selectionSets.columns.has(startId) && selectionSets.columns.has(endId);
493→    })
494→    .map((beam) => rebaseBeam(beam));
495→
496→  content.stairs = (floor.stairs || [])
497→    .filter((stair) => selectionSets.stairs.has(stair.id))
498→    .map((stair) => rebaseStair(stair, anchor));
499→
500→  content.annotations = (floor.annotations || [])
501→    .filter((annotation) => selectionSets.annotations.has(annotation.id))
502→    .map((annotation) => rebaseAnnotation(annotation, anchor));
503→
504→  content.slabs = (floor.slabs || [])
505→    .filter((slab) => selectionSets.slabs.has(slab.id))
506→    .map((slab) => rebaseSlab(slab, anchor));
507→
508→  content.sectionCuts = (floor.sectionCuts || [])
509→    .filter((sectionCut) => selectionSets.sectionCuts.has(sectionCut.id))
510→    .map((sectionCut) => rebaseSectionCut(sectionCut, anchor));
511→
512→  content.rooms = (floor.rooms || [])
513→    .filter((room) => selectionSets.rooms.has(room.id))
514→    .map((room) => rebaseRoom(room, anchor));
515→
516→  return {
517→    sourceProjectId: projectId,
518→    sourceFloorId: floorId,
519→    sourceBounds: regionSelection?.bounds || null,
520→    sourceSelectionCount: regionSelection?.objectCount || 0,
521→    bounds: buildContentBounds(content),
522→    anchor,
523→    objectCount: countContent(content),
524→    content,
525→  };
526→}
527→
528→export function materializePlanClipboardContent(payload, placementPoint) {
529→  if (!payload) return null;
530→  return translateContent(payload.content, placementPoint);
531→}
