533→export function cutPlanSelectionFromFloor(floor, selection) {
534→  const selectionSets = toIdSetMap(selection);
535→  const selectedWallIds = selectionSets.walls;
536→  const selectedColumnIds = selectionSets.columns;
537→
538→  const nextWalls = (floor.walls || [])
539→    .filter((wall) => !selectedWallIds.has(wall.id))
540→    .map((wall) => ({
541→      ...wall,
542→      startAttachment: selectedColumnIds.has(wall.startAttachment?.columnId)
543→        ? null
544→        : cloneAttachment(wall.startAttachment),
545→      endAttachment: selectedColumnIds.has(wall.endAttachment?.columnId)
546→        ? null
547→        : cloneAttachment(wall.endAttachment),
548→    }));
549→
550→  const nextDoors = (floor.doors || []).filter((door) => (
551→    !selectionSets.doors.has(door.id) && !selectedWallIds.has(door.wallId)
552→  ));
553→
554→  const nextWindows = (floor.windows || []).filter((window_) => (
555→    !selectionSets.windows.has(window_.id) && !selectedWallIds.has(window_.wallId)
556→  ));
557→
558→  const nextColumns = (floor.columns || []).filter((column) => !selectedColumnIds.has(column.id));
559→  const nextColumnIds = new Set(nextColumns.map((column) => column.id));
560→
561→  const nextBeams = (floor.beams || []).filter((beam) => (
562→    !selectionSets.beams.has(beam.id) &&
563→    nextColumnIds.has(beam.startRef?.id) &&
564→    nextColumnIds.has(beam.endRef?.id)
565→  ));
566→
567→  return {
568→    ...floor,
569→    walls: nextWalls,
570→    doors: nextDoors,
571→    windows: nextWindows,
572→    columns: nextColumns,
573→    beams: nextBeams,
574→    stairs: (floor.stairs || []).filter((stair) => !selectionSets.stairs.has(stair.id)),
575→    annotations: (floor.annotations || []).filter((annotation) => !selectionSets.annotations.has(annotation.id)),
576→    slabs: (floor.slabs || []).filter((slab) => !selectionSets.slabs.has(slab.id)),
577→    sectionCuts: (floor.sectionCuts || []).filter((sectionCut) => !selectionSets.sectionCuts.has(sectionCut.id)),
578→    rooms: (floor.rooms || []).filter((room) => !selectionSets.rooms.has(room.id)),
579→  };
580→}
581→
582→export function pastePlanClipboardOnFloor({ floor, floorId, payload, placementPoint }) {
583→  const translated = materializePlanClipboardContent(payload, placementPoint);
584→  if (!translated) {
585→    return {
586→      nextFloor: floor,
587→      insertedSelection: createEmptyPlanSelection(),
588→      insertedCount: 0,
589→      insertedBounds: null,
590→    };
591→  }
592→
593→  const idMaps = PLAN_KEYS.reduce((acc, key) => {
594→    acc[key] = new Map();
595→    return acc;
596→  }, {});
597→  const insertedSelection = createEmptyPlanSelection();
598→
599→  const nextColumns = (translated.columns || []).map((column) => {
600→    const nextId = generateId(idPrefixForKey('columns'));
601→    idMaps.columns.set(column.id, nextId);
602→    insertedSelection.columns.push(nextId);
603→    return {
604→      ...column,
605→      id: nextId,
606→    };
607→  });
608→
609→  const nextWalls = (translated.walls || []).map((wall) => {
610→    const nextId = generateId(idPrefixForKey('walls'));
611→    idMaps.walls.set(wall.id, nextId);
612→    insertedSelection.walls.push(nextId);
613→    return {
614→      ...wall,
615→      id: nextId,
616→      startAttachment: cloneAttachment(wall.startAttachment, idMaps.columns.get(wall.startAttachment?.columnId) || null),
617→      endAttachment: cloneAttachment(wall.endAttachment, idMaps.columns.get(wall.endAttachment?.columnId) || null),
618→    };
619→  });
620→
621→  const nextDoors = (translated.doors || []).flatMap((door) => {
622→    const nextWallId = idMaps.walls.get(door.wallId);
623→    if (!nextWallId) return [];
624→    const nextId = generateId(idPrefixForKey('doors'));
625→    idMaps.doors.set(door.id, nextId);
626→    insertedSelection.doors.push(nextId);
627→    return [{
628→      ...door,
629→      id: nextId,
630→      wallId: nextWallId,
631→    }];
632→  });
633→
634→  const nextWindows = (translated.windows || []).flatMap((window_) => {
635→    const nextWallId = idMaps.walls.get(window_.wallId);
636→    if (!nextWallId) return [];
637→    const nextId = generateId(idPrefixForKey('windows'));
638→    idMaps.windows.set(window_.id, nextId);
639→    insertedSelection.windows.push(nextId);
640→    return [{
641→      ...window_,
642→      id: nextId,
643→      wallId: nextWallId,
644→    }];
645→  });
646→
647→  const nextBeams = (translated.beams || []).flatMap((beam) => {
648→    const nextStartId = idMaps.columns.get(beam.startRef?.id);
649→    const nextEndId = idMaps.columns.get(beam.endRef?.id);
650→    if (!nextStartId || !nextEndId) return [];
651→
652→    const nextId = generateId(idPrefixForKey('beams'));
653→    idMaps.beams.set(beam.id, nextId);
654→    insertedSelection.beams.push(nextId);
655→
656→    return [{
657→      ...beam,
658→      id: nextId,
659→      startRef: beam.startRef ? { ...beam.startRef, id: nextStartId } : null,
660→      endRef: beam.endRef ? { ...beam.endRef, id: nextEndId } : null,
661→    }];
662→  });
663→
664→  const nextStairs = (translated.stairs || []).map((stair) => {
665→    const nextId = generateId(idPrefixForKey('stairs'));
666→    idMaps.stairs.set(stair.id, nextId);
667→    insertedSelection.stairs.push(nextId);
668→    return {
669→      ...stair,
670→      id: nextId,
671→      floorRelation: {
672→        fromFloorId: floorId,
673→        toFloorId: null,
674→      },
675→    };
676→  });
677→
678→  const nextAnnotations = (translated.annotations || []).map((annotation) => {
679→    const nextId = generateId(idPrefixForKey('annotations'));
680→    idMaps.annotations.set(annotation.id, nextId);
681→    insertedSelection.annotations.push(nextId);
682→    return {
683→      ...annotation,
684→      id: nextId,
685→    };
686→  });
687→
688→  const nextSlabs = (translated.slabs || []).map((slab) => {
689→    const nextId = generateId(idPrefixForKey('slabs'));
690→    idMaps.slabs.set(slab.id, nextId);
691→    insertedSelection.slabs.push(nextId);
692→    return {
693→      ...slab,
694→      id: nextId,
695→      floorId,
696→    };
697→  });
698→
699→  const nextSectionCuts = (translated.sectionCuts || []).map((sectionCut) => {
700→    const nextId = generateId(idPrefixForKey('sectionCuts'));
701→    idMaps.sectionCuts.set(sectionCut.id, nextId);
702→    insertedSelection.sectionCuts.push(nextId);
703→    return {
704→      ...sectionCut,
705→      id: nextId,
706→    };
707→  });
708→
709→  const nextRooms = (translated.rooms || []).map((room) => {
710→    const nextId = generateId(idPrefixForKey('rooms'));
711→    idMaps.rooms.set(room.id, nextId);
712→    insertedSelection.rooms.push(nextId);
713→    return {
714→      ...room,
715→      id: nextId,
716→    };
717→  });
718→
719→  const insertedContent = {
720→    walls: nextWalls,
721→    doors: nextDoors,
722→    windows: nextWindows,
723→    columns: nextColumns,
724→    beams: nextBeams,
725→    stairs: nextStairs,
726→    annotations: nextAnnotations,
727→    slabs: nextSlabs,
728→    sectionCuts: nextSectionCuts,
729→    rooms: nextRooms,
730→  };
731→
732→  return {
733→    nextFloor: {
734→      ...floor,
735→      walls: [...(floor.walls || []), ...nextWalls],
736→      doors: [...(floor.doors || []), ...nextDoors],
737→      windows: [...(floor.windows || []), ...nextWindows],
738→      columns: [...(floor.columns || []), ...nextColumns],
739→      beams: [...(floor.beams || []), ...nextBeams],
740→      stairs: [...(floor.stairs || []), ...nextStairs],
741→      annotations: [...(floor.annotations || []), ...nextAnnotations],
742→      slabs: [...(floor.slabs || []), ...nextSlabs],
743→      sectionCuts: [...(floor.sectionCuts || []), ...nextSectionCuts],
744→      rooms: [...(floor.rooms || []), ...nextRooms],
745→    },
746→    insertedSelection,
747→    insertedCount: countSelection(insertedSelection),
748→    insertedBounds: buildContentBounds(insertedContent),
749→  };
750→}
751→
752→export function clonePlanSelection(selection) {
753→  return cloneSelection(selection);
754→}
