            data-id={landing.id}
            data-type="landing"
            points={points}
            fill="rgba(160, 165, 175, 0.25)"
            stroke="#666"
            strokeWidth={1}
            vectorEffect="non-scaling-stroke"
          />
        );
      })}
    </g>
  );
}

