232→function createOpeningInsertDescriptor(opening) {
233→  return createBoxDescriptor(
234→    opening.id,
235→    opening.kind,
236→    opening.centerPoint,
237→    {
238→      x: opening.visibleWidth,
239→      y: opening.visibleHeight,
240→      z: getInsertThickness(opening.kind, opening.wallThickness),
241→    },
242→    opening.visibleBaseElevation,
243→    opening.angle,
244→    {
245→      sourceId: opening.sourceId,
246→      floorId: opening.metadata.floorId,
247→      wallId: opening.wallId,
