298→export function buildFloorPreviewObjects(floor) {
299→  const floorLevel = getFloorElevation(floor);
300→  const wallContexts = buildWallPreviewContexts(floor, floorLevel);
301→
302→  return [
303→    ...buildSlabObjects(floor),
304→    ...buildWallObjects(wallContexts),
305→    ...buildColumnObjects(floor, floorLevel),
306→    ...buildBeamObjects(floor),
307→    ...buildStairObjects(floor, floorLevel),
308→    ...buildLandingObjects(floor, floorLevel),
309→    ...buildDoorObjects(wallContexts),
310→    ...buildWindowObjects(wallContexts),
311→  ];
