  1→import * as THREE from 'three';
  2→
  3→function planPointToWorld(point, elevation = 0) {
  4→  return new THREE.Vector3(point.x, elevation, point.y);
  5→}
  6→
  7→function planAngleToWorldRotation(angle = 0) {
  8→  return -angle;
  9→}
 10→
 11→function createShape(outline) {
 12→  const shape = new THREE.Shape();
 13→  outline.forEach((point, index) => {
 14→    if (index === 0) {
 15→      // Flip plan Y here so the rotated extrusion preserves the blueprint's handedness.
 16→      shape.moveTo(point.x, -point.y);
 17→      return;
 18→    }
 19→    shape.lineTo(point.x, -point.y);
 20→  });
 21→  shape.closePath();
 22→  return shape;
 23→}
 24→
 25→function addOutline(object3d, materialPalette) {
 26→  if (!object3d.geometry) return;
 27→  const edges = new THREE.EdgesGeometry(object3d.geometry, 20);
 28→  const outline = new THREE.LineSegments(edges, materialPalette.outline);
 29→  object3d.add(outline);
 30→}
 31→
 32→function createPrismObject(descriptor, materialPalette) {
 33→  const geometry = new THREE.ExtrudeGeometry(createShape(descriptor.outline), {
 34→    depth: descriptor.height,
 35→    bevelEnabled: false,
 36→    curveSegments: 1,
 37→    steps: 1,
 38→  });
 39→
 40→  geometry.rotateX(-Math.PI / 2);
 41→  geometry.translate(0, descriptor.baseElevation, 0);
 42→
 43→  const mesh = new THREE.Mesh(geometry, materialPalette[descriptor.materialKey]);
 44→  mesh.castShadow = true;
 45→  mesh.receiveShadow = true;
 46→  addOutline(mesh, materialPalette);
 47→  return mesh;
 48→}
 49→
 50→function createBoxObject(descriptor, materialPalette) {
 51→  const geometry = new THREE.BoxGeometry(
 52→    Math.max(descriptor.size.x, 1),
 53→    Math.max(descriptor.size.y, 1),
 54→    Math.max(descriptor.size.z, 1)
 55→  );
 56→  const mesh = new THREE.Mesh(geometry, materialPalette[descriptor.materialKey]);
 57→  const center = planPointToWorld(
 58→    descriptor.center,
 59→    descriptor.baseElevation + descriptor.size.y / 2
 60→  );
 61→  mesh.position.copy(center);
 62→  mesh.rotation.y = planAngleToWorldRotation(descriptor.rotation);
 63→  mesh.castShadow = true;
 64→  mesh.receiveShadow = true;
 65→  addOutline(mesh, materialPalette);
 66→  return mesh;
 67→}
 68→
 69→function createStairObject(descriptor, materialPalette) {
 70→  const group = new THREE.Group();
 71→  const risers = Math.max(1, descriptor.numberOfRisers || 1);
 72→
 73→  for (let index = 0; index < risers; index += 1) {
 74→    const geometry = new THREE.BoxGeometry(
 75→      Math.max(descriptor.treadDepth, 1),
 76→      Math.max(descriptor.riserHeight, 1),
 77→      Math.max(descriptor.width, 1)
 78→    );
 79→    const step = new THREE.Mesh(geometry, materialPalette[descriptor.materialKey]);
 80→    step.position.set(
 81→      descriptor.treadDepth * (index + 0.5),
 82→      descriptor.riserHeight * (index + 0.5),
 83→      0
 84→    );
 85→    step.castShadow = true;
 86→    step.receiveShadow = true;
 87→    addOutline(step, materialPalette);
 88→    group.add(step);
 89→  }
 90→
 91→  group.position.copy(planPointToWorld(descriptor.startPoint, descriptor.baseElevation));
 92→  group.rotation.y = planAngleToWorldRotation(descriptor.angle * Math.PI / 180);
 93→  return group;
 94→}
 95→
 96→function createWindowObject(descriptor, materialPalette) {
 97→  const group = new THREE.Group();
 98→  const { x: width, y: height, z: depth } = descriptor.size;
 99→
100→  const frameWidth = Math.max(40, Math.min(width, height) * 0.06);
101→  const glassThickness = Math.max(depth * 0.15, 10);
102→  const mullionWidth = frameWidth * 0.5;
103→
104→  const frameMaterial = materialPalette.windowFrame;
105→  const glassMaterial = materialPalette.window;
106→
107→  // Frame rails
108→  const frameRails = [
109→    // top
110→    { sx: width, sy: frameWidth, sz: depth, px: 0, py: (height - frameWidth) / 2, pz: 0 },
111→    // bottom
112→    { sx: width, sy: frameWidth, sz: depth, px: 0, py: -(height - frameWidth) / 2, pz: 0 },
113→    // left
114→    { sx: frameWidth, sy: height - frameWidth * 2, sz: depth, px: -(width - frameWidth) / 2, py: 0, pz: 0 },
115→    // right
116→    { sx: frameWidth, sy: height - frameWidth * 2, sz: depth, px: (width - frameWidth) / 2, py: 0, pz: 0 },
117→  ];
118→
119→  for (const rail of frameRails) {
120→    const geo = new THREE.BoxGeometry(
121→      Math.max(rail.sx, 1), Math.max(rail.sy, 1), Math.max(rail.sz, 1)
122→    );
123→    const mesh = new THREE.Mesh(geo, frameMaterial);
124→    mesh.position.set(rail.px, rail.py, rail.pz);
125→    mesh.castShadow = true;
126→    mesh.receiveShadow = true;
127→    addOutline(mesh, materialPalette);
128→    group.add(mesh);
129→  }
130→
131→  // Glass pane (no outline — dark edges look wrong on glass)
132→  const innerW = width - frameWidth * 2;
133→  const innerH = height - frameWidth * 2;
134→  const glassGeo = new THREE.BoxGeometry(
135→    Math.max(innerW, 1), Math.max(innerH, 1), Math.max(glassThickness, 1)
136→  );
137→  const glassMesh = new THREE.Mesh(glassGeo, glassMaterial);
138→  glassMesh.castShadow = false;
139→  glassMesh.receiveShadow = true;
140→  group.add(glassMesh);
141→
142→  // Type-specific mullions
143→  const windowType = descriptor.windowType || 'standard';
144→  const mullions = [];
145→
146→  if (windowType === 'standard') {
147→    // 2 horizontal bars at 1/3 and 2/3 height
148→    const thirdH = innerH / 3;
149→    mullions.push(
150→      { sx: innerW, sy: mullionWidth, sz: depth, px: 0, py: -thirdH / 2 + innerH / 6, pz: 0 },
151→    );
152→    mullions.push(
153→      { sx: innerW, sy: mullionWidth, sz: depth, px: 0, py: thirdH / 2 - innerH / 6, pz: 0 },
154→    );
155→    // Positions: at -innerH/6 and +innerH/6 from center = 1/3 and 2/3 of inner height
156→    mullions.length = 0; // clear and redo cleanly
157→    mullions.push(
158→      { sx: innerW, sy: mullionWidth, sz: depth, px: 0, py: -innerH / 2 + innerH / 3, pz: 0 },
159→      { sx: innerW, sy: mullionWidth, sz: depth, px: 0, py: -innerH / 2 + (innerH * 2) / 3, pz: 0 },
160→    );
161→  } else if (windowType === 'casement') {
162→    // 1 vertical center bar
163→    mullions.push(
164→      { sx: mullionWidth, sy: innerH, sz: depth, px: 0, py: 0, pz: 0 },
165→    );
166→  } else if (windowType === 'awning') {
167→    // 1 horizontal bar at ~30% from top
168→    mullions.push(
169→      { sx: innerW, sy: mullionWidth, sz: depth, px: 0, py: innerH / 2 - innerH * 0.3, pz: 0 },
170→    );
171→  } else if (windowType === 'jalousie') {
172→    // 5 evenly-spaced horizontal bars
173→    for (let i = 1; i <= 5; i++) {
174→      const y = -innerH / 2 + (innerH * i) / 6;
175→      mullions.push(
176→        { sx: innerW, sy: mullionWidth, sz: depth, px: 0, py: y, pz: 0 },
177→      );
178→    }
179→  }
180→  // 'fixed' — no mullions
181→
182→  for (const m of mullions) {
183→    const geo = new THREE.BoxGeometry(
184→      Math.max(m.sx, 1), Math.max(m.sy, 1), Math.max(m.sz, 1)
185→    );
186→    const mesh = new THREE.Mesh(geo, frameMaterial);
187→    mesh.position.set(m.px, m.py, m.pz);
188→    mesh.castShadow = true;
189→    mesh.receiveShadow = true;
190→    addOutline(mesh, materialPalette);
191→    group.add(mesh);
192→  }
193→
194→  // Position and rotate the group
195→  const center = planPointToWorld(
196→    descriptor.center,
197→    descriptor.baseElevation + height / 2
198→  );
199→  group.position.copy(center);
200→  group.rotation.y = planAngleToWorldRotation(descriptor.rotation);
201→
202→  return group;
203→}
204→
205→function createObjectForDescriptor(descriptor, materialPalette) {
206→  if (descriptor.geometry === 'prism') {
207→    return createPrismObject(descriptor, materialPalette);
208→  }
209→
210→  if (descriptor.geometry === 'stair') {
211→    return createStairObject(descriptor, materialPalette);
212→  }
213→
214→  if (descriptor.geometry === 'window') {
215→    return createWindowObject(descriptor, materialPalette);
216→  }
217→
218→  return createBoxObject(descriptor, materialPalette);
219→}
