 15→function resolvePoint(modelPos, snapEnabled) {
 16→  if (!snapEnabled) return { x: modelPos.x, y: modelPos.y };
 17→  return {
 18→    x: snapToGrid(modelPos.x),
 19→    y: snapToGrid(modelPos.y),
 20→  };
 21→}
