 40→      let point = resolvePoint(modelPos, snapEnabled);
 41→      const floor = getFloor(activeFloorId);
 42→      const landings = floor?.landings || [];
 43→      const snapDist = SNAP_DISTANCE_PX / (viewport?.zoom || 0.1);
 44→
 45→      if (!toolState.stairStartPoint) {
 46→        // Try snap start to landing edge
 47→        let startLandingAttachment = null;
 48→        const startSnap = snapToLandingEdge(point, landings, snapDist);
 49→        if (startSnap) {
 50→          point = startSnap.point;
 51→          startLandingAttachment = { landingId: startSnap.landingId, edge: startSnap.edge };
 52→        }
 53→
 54→        editorDispatch({
 55→          type: 'UPDATE_TOOL_STATE',
 56→          payload: {
 57→            stairStartPoint: point,
 58→            stairPreviewPoint: point,
 59→            stairPreviewAngle: 0,
 60→            startLandingAttachment,
 61→          },
 62→        });
 63→        editorDispatch({ type: 'SET_STATUS_MESSAGE', message: 'Click again to set stair direction.' });
 64→        return;
 65→      }
 66→
 67→      if (distance(toolState.stairStartPoint, point) < GRID_MINOR / 2) {
 68→        editorDispatch({ type: 'SET_STATUS_MESSAGE', message: 'Choose a direction farther from the stair start.' });
 69→        return;
 70→      }
 71→
 72→      const angle = getAngleDegrees(toolState.stairStartPoint, point);
 73→
 74→      // Check if end point snaps to a landing
 75→      let endLandingAttachment = null;
 76→      const tempStair = {
 77→        startPoint: toolState.stairStartPoint,
 78→        numberOfRisers: 18,
 79→        treadDepth: 280,
 80→        direction: { angle },
 81→        width: 1000,
 82→      };
 83→      const run = stairRun(tempStair);
 84→      const dir = stairDirectionVector(tempStair);
 85→      const endPoint = add(toolState.stairStartPoint, scale(dir, run));
 86→      const endSnap = snapToLandingEdge(endPoint, landings, snapDist);
 87→      if (endSnap) {
 88→        endLandingAttachment = { landingId: endSnap.landingId, edge: endSnap.edge };
 89→      }
 90→
 91→      const stair = createStair(
 92→        toolState.stairStartPoint,
 93→        undefined,
 94→        undefined,
 95→        undefined,
 96→        undefined,
 97→        { angle },
 98→        { fromFloorId: activeFloorId, toFloorId: activeFloorId },
 99→        {
100→          startLandingAttachment: toolState.startLandingAttachment || null,
101→          endLandingAttachment,
102→        }
103→      );
104→
105→      dispatch({ type: 'STAIR_ADD', floorId: activeFloorId, stair });
106→      editorDispatch({ type: 'SELECT_OBJECT', id: stair.id, objectType: 'stair' });
107→      resetStairTool(editorDispatch);
108→      editorDispatch({ type: 'SET_STATUS_MESSAGE', message: 'Stair created.' });
109→    },
110→
111→    onMouseMove(modelPos, e, toolState) {
112→      if (!toolState.stairStartPoint) return;
113→      const point = resolvePoint(modelPos, snapEnabled);
114→      editorDispatch({
115→        type: 'UPDATE_TOOL_STATE',
116→        payload: {
117→          stairPreviewPoint: point,
118→          stairPreviewAngle: getAngleDegrees(toolState.stairStartPoint, point),
119→        },
120→      });
121→    },
122→
123→    onKeyDown(e) {
124→      if (e.key !== 'Escape') return;
125→      resetStairTool(editorDispatch);
126→      editorDispatch({ type: 'SET_TOOL', tool: 'select' });
127→    },
128→
129→    getCursor() {
130→      return 'crosshair';
131→    },
132→  };
133→}
