 1→export function disposeScene(root, options = {}) {
 2→  if (!root) return;
 3→
 4→  const disposeMaterials = options.disposeMaterials ?? false;
 5→
 6→  root.traverse((node) => {
 7→    node.geometry?.dispose?.();
 8→
 9→    if (!disposeMaterials) return;
